msg.headers = Object.assign({}, msg.headers, {
  "Content-Type": "application/json; charset=utf-8",
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type, Authorization"
});
if (msg.statusCode == null) msg.statusCode = 200;
return msg;

const q = (msg.req && msg.req.query) ? msg.req.query : {};
const from = q.from;
const limitRaw = q.limit;
const limit = limitRaw ? Math.max(1, Math.min(100, Number(limitRaw))) : 100;

if (from) {
  msg.topic = `
SELECT
  Sessions.start_date as "Start Date/Time",
  Sessions.session_id as "Session ID",
  Locations.name as "Location",
  Chargers.name as "Charger",
  Connectors.connector_type as "Connector",
  ROUND(Sessions.kwh,2) as "Energy (KWH)",
  ROUND(Sessions.amount,2) as "Amount (JOD)",
  Sessions.user_id as "mobile"
FROM Sessions
RIGHT JOIN Connectors ON Connectors.connector_id = Sessions.connector_id
RIGHT JOIN Chargers ON Chargers.charger_id = Sessions.charger_id
RIGHT JOIN Locations ON Locations.location_id = Chargers.location_id
WHERE Sessions.active=1 AND Sessions.start_date > ?
GROUP BY Sessions.session_id
ORDER BY Sessions.session_id DESC
LIMIT ?;
`;
  msg.payload = [from, limit];
} else {
  msg.topic = `
SELECT
  Sessions.start_date as "Start Date/Time",
  Sessions.session_id as "Session ID",
  Locations.name as "Location",
  Chargers.name as "Charger",
  Connectors.connector_type as "Connector",
  ROUND(Sessions.kwh,2) as "Energy (KWH)",
  ROUND(Sessions.amount,2) as "Amount (JOD)",
  Sessions.user_id as "mobile"
FROM Sessions
RIGHT JOIN Connectors ON Connectors.connector_id = Sessions.connector_id
RIGHT JOIN Chargers ON Chargers.charger_id = Sessions.charger_id
RIGHT JOIN Locations ON Locations.location_id = Chargers.location_id
WHERE Sessions.active=1
GROUP BY Sessions.session_id
ORDER BY Sessions.session_id DESC
LIMIT ?;
`;
  msg.payload = [limit];
}
return msg;

