const msgOcpp = RED.util.cloneMessage(msg);
msgOcpp.statsKey = "ocpp";
msgOcpp.topic = `
SELECT
  (SELECT COUNT(*) FROM Sessions WHERE active=1 AND charging=1) AS activeSessions,
  (SELECT IFNULL(FLOOR((busy/total)*100),0) FROM (SELECT (SELECT COUNT(*) FROM Connectors WHERE enabled=1) AS total, (SELECT COUNT(*) FROM Connectors WHERE status='busy') AS busy) t) AS utilization,
  (SELECT COUNT(*) FROM Chargers WHERE LOWER(status)='online') AS chargersOnline,
  0 AS payments,
  0 AS faults,
  0 AS revenue,
  0 AS tariffAC,
  0 AS tariffDC
`;
msgOcpp.payload = [];

const msgIon = RED.util.cloneMessage(msg);
msgIon.statsKey = "ion";
msgIon.topic = `
SELECT
  (SELECT COUNT(*) FROM user_profiles WHERE creation_date > CURDATE()) AS newUsers,
  (SELECT COUNT(*) FROM charger_sessions WHERE start_date > CURDATE() AND amount>0) AS sessions,
  (SELECT IFNULL(SUM(PaidAmt),0) FROM BLRPMTNTFRQ WHERE PmtStatus = 'PmtNew' AND TmStp > CURDATE()) AS eFawateerCom,
  (SELECT IFNULL(SUM(amount),0) FROM ni_orders WHERE status='success' AND \`time\` > CURDATE()) AS ni,
  (SELECT IFNULL(SUM(amount),0) FROM orange_money_transactions WHERE \`timestamp\` > CURDATE()) AS orangeMoney,
  (SELECT IFNULL(ROUND(SUM(amount),2),0) FROM charger_sessions WHERE amount>0 AND end_date > CURDATE()) AS expendature
`;
msgIon.payload = [];

return [msgOcpp, msgIon];

const key = msg.statsKey || "part";
const row = (Array.isArray(msg.payload) && msg.payload[0]) ? msg.payload[0] : {};
msg.topic = key;
msg.payload = row;
return msg;

const parts = msg.payload || {};
const ocpp = parts.ocpp || {};
const ion = parts.ion || {};

const eFawateerCom = Number(ion.eFawateerCom || 0);
const ni = Number(ion.ni || 0);
const orangeMoney = Number(ion.orangeMoney || 0);

msg.payload = {
  activeSessions: Number(ocpp.activeSessions || 0),
  utilization: Number(ocpp.utilization || 0),
  chargersOnline: Number(ocpp.chargersOnline || 0),
  newUsers: Number(ion.newUsers || 0),
  sessions: Number(ion.sessions || 0),
  payments: Number(ocpp.payments || 0),
  faults: Number(ocpp.faults || 0),
  revenue: Number(ocpp.revenue || 0),
  tariffAC: Number(ocpp.tariffAC || 0),
  tariffDC: Number(ocpp.tariffDC || 0),
  eFawateerCom,
  ni,
  orangeMoney,
  totalCashIn: eFawateerCom + ni + orangeMoney,
  expendature: Number(ion.expendature || 0)
};
msg.statusCode = 200;
return msg;

const q = (msg.req && msg.req.query) ? msg.req.query : {};
const orgId = q.organizationId || q.organization_id;
if (!orgId) { msg.statusCode = 200; msg.payload = []; return msg; }
msg.topic = "SELECT location_id as value, name as label FROM Locations WHERE organization_id = ?;";
msg.payload = [orgId];
return msg;

const q = (msg.req && msg.req.query) ? msg.req.query : {};
