const q = (msg.req && msg.req.query) ? msg.req.query : {};
const chargerId = q.chargerId || q.charger_id;
if (!chargerId) { msg.statusCode = 400; msg.payload = { error: "chargerId is required" }; return msg; }
msg.topic = "SELECT status FROM Chargers WHERE charger_id = ? LIMIT 1;";
msg.payload = [chargerId];
return msg;

const row = (Array.isArray(msg.payload) && msg.payload[0]) ? msg.payload[0] : {};
msg.statusCode = 200;
msg.payload = { status: row.status || "" };
return msg;

const q = (msg.req && msg.req.query) ? msg.req.query : {};
const connectorId = q.connectorId || q.connector_id;
if (!connectorId) { msg.statusCode = 400; msg.payload = { error: "connectorId is required" }; return msg; }
msg.topic = "SELECT status FROM Connectors WHERE connector_id = ? LIMIT 1;";
msg.payload = [connectorId];
return msg;

const q = (msg.req && msg.req.query) ? msg.req.query : {};
const body = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};
const chargerId = q.chargerId || body.chargerId;
const command = q.command || body.command;

const allowed = ['restart','stop','unlock'];
if (!chargerId) { msg.statusCode = 400; msg.payload = { success:false, message:'chargerId is required' }; return msg; }
if (!allowed.includes(command)) { msg.statusCode = 400; msg.payload = { success:false, message:'command must be restart|stop|unlock' }; return msg; }

msg.statusCode = 200;
msg.payload = { success:true, message:`Command '${command}' sent to charger ${chargerId}` };
return msg;

const q = (msg.req && msg.req.query) ? msg.req.query : {};
const mobile = q.mobile;
if (!mobile || String(mobile).length < 10) { msg.statusCode = 400; msg.payload = { error:'mobile is required (>=10 digits)' }; return msg; }
msg.topic = 'SELECT mobile, first_name, last_name, ROUND(balance,2) as balance, language, device_id FROM user_profiles WHERE mobile = ? LIMIT 1;';
msg.payload = [mobile];
